#include<bits/stdc++.h>
using namespace std;
const int maxn=20;
int f[1<<maxn],n,m,k;
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m>>k;
	fill(f+1,f+(1<<m),n+1);
	for(int i=1;i<=n;i++){
		int s=0;
		for(int j=1,x;j<=k;j++){
			cin>>x;
			s|=1<<x-1;
		}
		for(int j=0;j<1<<m;j++){
			f[s|j]=min(f[s|j],f[j]+1);
		}
	}
	if(f[(1<<m)-1]>n){
		cout<<-1;
	}else{
		cout<<f[(1<<m)-1];
	}
	return 0;
}
